/**
 * Slack bot setup logic.
 *
 * Pure, side-effect-light helpers for the `get-claudia slack` subcommand.
 * Interactive prompting lives in index.js; everything here is testable in
 * isolation (env merging, validation, key generation, docker detection).
 */

import { existsSync, readFileSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { randomBytes } from 'node:crypto';
import { spawn } from 'node:child_process';

/**
 * The secrets a user must supply themselves. These cannot be auto-generated
 * because they come from the user's own Slack app and Anthropic account.
 */
export const REQUIRED_SECRETS = [
  'SLACK_BOT_TOKEN',
  'SLACK_APP_TOKEN',
  'SLACK_SIGNING_SECRET',
  'ANTHROPIC_API_KEY',
];

/**
 * Validate a Slack/Anthropic secret against its expected prefix.
 * Returns null if valid, or a human-readable error string if not.
 * Empty values are reported as required.
 */
export function validateSecret(name, value) {
  const v = (value || '').trim();
  if (!v) return `${name} is required.`;

  const prefixes = {
    SLACK_BOT_TOKEN: 'xoxb-',
    SLACK_APP_TOKEN: 'xapp-',
    ANTHROPIC_API_KEY: 'sk-ant-',
  };

  const expected = prefixes[name];
  if (expected && !v.startsWith(expected)) {
    return `${name} should start with "${expected}" (got "${v.slice(0, 6)}...").`;
  }
  // SLACK_SIGNING_SECRET has no fixed prefix; just require non-empty.
  return null;
}

/**
 * Generate a random base64 key suitable for MEMORY_API_KEY (32 bytes).
 */
export function generateApiKey() {
  return randomBytes(32).toString('base64');
}

/**
 * Generate a random hex secret suitable for AUTH_SECRET (32 bytes).
 */
export function generateHexSecret() {
  return randomBytes(32).toString('hex');
}

/**
 * Parse a .env file body into a flat key→value map.
 * Ignores comments and blank lines. Values are taken verbatim (no unquoting),
 * which is fine for our generated files.
 */
export function parseEnv(body) {
  const out = {};
  if (!body) return out;
  for (const rawLine of body.split('\n')) {
    const line = rawLine.trim();
    if (!line || line.startsWith('#')) continue;
    const eq = line.indexOf('=');
    if (eq === -1) continue;
    const key = line.slice(0, eq).trim();
    const val = line.slice(eq + 1).trim();
    if (key) out[key] = val;
  }
  return out;
}

/**
 * Build the .env file contents for a Slack/Docker deployment.
 *
 * @param {object} opts
 * @param {object} opts.secrets   - User-provided secrets (REQUIRED_SECRETS)
 * @param {object} [opts.existing] - Existing env map to preserve keys from
 * @param {object} [opts.calendar] - Optional { clientId, clientSecret }
 * @returns {string} The full .env body, ready to write.
 */
export function buildEnvContent({ secrets = {}, existing = {}, calendar = null } = {}) {
  // Preserve previously generated keys so re-running setup doesn't rotate them
  // (rotating MEMORY_API_KEY would orphan the bot from the daemon until both restart).
  const memoryKey = existing.MEMORY_API_KEY || generateApiKey();
  const authSecret = existing.AUTH_SECRET || generateHexSecret();

  const lines = [
    '# Claudia environment - generated by `get-claudia slack`',
    '# Never commit this file. It contains secrets.',
    '',
    '# --- Required: Slack ---',
    `SLACK_BOT_TOKEN=${secrets.SLACK_BOT_TOKEN || ''}`,
    `SLACK_APP_TOKEN=${secrets.SLACK_APP_TOKEN || ''}`,
    `SLACK_SIGNING_SECRET=${secrets.SLACK_SIGNING_SECRET || ''}`,
    '# Socket Mode needs no public URL. Recommended for self-hosting.',
    'SLACK_SOCKET_MODE=true',
    '',
    '# --- Required: Anthropic ---',
    `ANTHROPIC_API_KEY=${secrets.ANTHROPIC_API_KEY || ''}`,
    'CLAUDE_MODEL=claude-sonnet-4-6',
    '',
    '# --- Auto-generated keys (do not edit) ---',
    `MEMORY_API_KEY=${memoryKey}`,
    `AUTH_SECRET=${authSecret}`,
    '',
    '# --- Memory daemon ---',
    'MEMORY_API_URL=http://localhost:3850',
    'MEMORY_RECALL_LIMIT=15',
    'OLLAMA_HOST=http://localhost:11434',
    '',
    '# --- Visualizer ---',
    'AUTH_DISABLED=true',
    'APP_URL=http://localhost:3849',
    '',
  ];

  if (calendar && calendar.clientId && calendar.clientSecret) {
    lines.push(
      '# --- Google Calendar (optional) ---',
      `GOOGLE_CLIENT_ID=${calendar.clientId}`,
      `GOOGLE_CLIENT_SECRET=${calendar.clientSecret}`,
      '',
    );
  }

  return lines.join('\n');
}

/**
 * Check whether a binary is runnable by invoking it with the given args.
 * Resolves true on exit code 0, false otherwise (including ENOENT).
 */
export function commandSucceeds(cmd, args = ['--version']) {
  return new Promise((resolve) => {
    let child;
    try {
      child = spawn(cmd, args, { stdio: 'ignore' });
    } catch {
      resolve(false);
      return;
    }
    child.on('close', (code) => resolve(code === 0));
    child.on('error', () => resolve(false));
  });
}

/**
 * Check that Docker is installed AND the daemon is running.
 * Returns { installed, running }.
 */
export async function checkDocker() {
  const installed = await commandSucceeds('docker', ['--version']);
  if (!installed) return { installed: false, running: false };
  // `docker info` only succeeds if the daemon is up.
  const running = await commandSucceeds('docker', ['info']);
  return { installed: true, running };
}

/**
 * Locate the bundled Slack app manifest. Returns the path or null.
 */
export function findManifest(binDir) {
  const candidate = join(binDir, '..', 'assets', 'slack-app-manifest.yaml');
  return existsSync(candidate) ? candidate : null;
}

/**
 * Read the existing .env at targetPath as a parsed map, or {} if absent.
 */
export function readExistingEnv(targetPath) {
  const envPath = join(targetPath, '.env');
  if (!existsSync(envPath)) return {};
  try {
    return parseEnv(readFileSync(envPath, 'utf-8'));
  } catch {
    return {};
  }
}

/**
 * Write the .env file to targetPath.
 */
export function writeEnv(targetPath, content) {
  writeFileSync(join(targetPath, '.env'), content.endsWith('\n') ? content : content + '\n');
}
